+function getUser(req) {
+  const id = Number(req.headers["x-user-id"] || 1);
+  return dbGet(`SELECT u.*, d.name AS department_name FROM users u LEFT JOIN departments d ON d.id=u.department_id WHERE u.id=${id} AND u.active=1`);
+}
+
+function requireRole(user, roles) {
+  if (!roles.includes(user.role)) {
+    const err = new Error("无权访问该资源");
+    err.status = 403;
+    throw err;
+  }
+}
+
+function audit(actor, action, type, id, detail = "") {
+  dbRun(`INSERT INTO audit_logs(actor_id,action,entity_type,entity_id,detail) VALUES(${actor?.id || "NULL"},${sqlQuote(action)},${sqlQuote(type)},${id || "NULL"},${sqlQuote(detail)})`);
+}
+
+function notify(userId, title, body) {
+  if (!userId) return;
+  dbRun(`INSERT INTO notifications(user_id,title,body) VALUES(${userId},${sqlQuote(title)},${sqlQuote(body)})`);
+}
+
+function addTicketEvent(ticketId, actorId, event, note = "") {
+  dbRun(`INSERT INTO ticket_events(ticket_id,actor_id,event,note) VALUES(${ticketId},${actorId || "NULL"},${sqlQuote(event)},${sqlQuote(note)})`);
+}
+
+function addAssetEvent(assetId, actorId, event, fromStatus, toStatus, note = "") {
+  dbRun(`INSERT INTO asset_events(asset_id,actor_id,event,from_status,to_status,note) VALUES(${assetId},${actorId || "NULL"},${sqlQuote(event)},${sqlQuote(fromStatus)},${sqlQuote(toStatus)},${sqlQuote(note)})`);
+}
+
+function availableCount(modelId) {
+  return dbGet(`SELECT COUNT(*) AS c FROM assets WHERE model_id=${modelId} AND status='available'`).c;
+}
+
+function calcNetValue(asset) {
+  const price = Number(asset.unit_price || 0);
+  const years = Math.max(0, (Date.now() - new Date(asset.purchase_date).getTime()) / (365 * 24 * 3600 * 1000));
+  return Math.max(0, price * (1 - Math.min(years / 5, 1)));
+}
+
+async function callLLM(task, userText, context) {
+  const base = process.env.AI_API_BASE_URL;
+  const key = process.env.AI_API_KEY;
+  const model = process.env.AI_MODEL || "deepseek-chat";
+  if (!base || !key) return null;
+  const res = await fetch(`${base.replace(/\/$/, "")}/chat/completions`, {
+    method: "POST",
+    headers: { "Content-Type": "application/json", Authorization: `Bearer ${key}` },
+    body: JSON.stringify({
+      model,
+      messages: [
+        { role: "system", content: "你是 IT 资产管理系统的 AI 助手。只输出简洁中文，涉及创建工单或执行动作时必须要求用户确认。" },
+        { role: "user", content: JSON.stringify({ task, userText, context }) }
+      ],
+      temperature: 0.2
+    })
+  });
+  if (!res.ok) throw new Error(`AI API 调用失败: ${res.status}`);
+  const data = await res.json();
+  return data.choices?.[0]?.message?.content || null;
+}
+
+function fallbackRecommend(text, models) {
+  const words = text.toLowerCase();
+  const scored = models.map(m => {
+    let score = 0;
+    for (const k of `${m.name} ${m.category} ${m.specs} ${m.keywords}`.toLowerCase().split(/\s+/)) {
+      if (k && words.includes(k)) score += 2;
+    }
+    if (words.includes("docker") && m.name.includes("ThinkPad")) score += 5;
+    if (words.includes("键盘") && m.category === "外设") score += 5;
+    if (words.includes("显示") || words.includes("屏幕")) score += m.category === "显示器" ? 5 : 0;
+    if (words.includes("测试") || words.includes("ios")) score += m.category === "测试机" ? 5 : 0;
+    return { ...m, score };
+  }).sort((a, b) => b.score - a.score || b.unit_price - a.unit_price);
+  return scored.slice(0, 3).map(m => ({
+    id: m.id,
+    name: m.name,
+    category: m.category,
+    specs: m.specs,
+    unit_price: m.unit_price,
+    available: availableCount(m.id),
+    reason: `${m.name} 与你的描述匹配，当前可用库存 ${availableCount(m.id)} 台。`
+  }));
+}
+
+function fallbackTriage(text) {
+  const hard = /屏幕|不亮|进水|摔|开不了机|异响|电池鼓包|无法充电|花屏/.test(text);
+  const severe = /开不了机|进水|不亮|电池鼓包/.test(text);
+  return {
+    type: hard ? "hardware" : "software",
+    severity: severe ? "high" : "normal",
+    suggestion: hard ? "疑似硬件问题，建议直接创建维修工单并交由 IT 检测。" : "可先尝试重启、释放磁盘空间、更新系统补丁；未解决再创建维修工单。"
+  };
+}
+
+async function readBody(req) {
+  const chunks = [];
+  for await (const chunk of req) chunks.push(chunk);
+  const raw = Buffer.concat(chunks).toString("utf8");
+  return raw ? JSON.parse(raw) : {};
+}
+
+function send(res, status, data) {
+  res.writeHead(status, { "Content-Type": "application/json; charset=utf-8" });
+  res.end(JSON.stringify(data));
+}
+
+function route(method, pattern, handler) {
+  const keys = [];
+  const regex = new RegExp("^" + pattern.replace(/:([^/]+)/g, (_, key) => {
+    keys.push(key);
+    return "([^/]+)";
+  }) + "$");
+  return { method, regex, keys, handler };
+}
+
+const routes = [
+  route("POST", "/api/login", async (req, res) => {
+    const body = await readBody(req);
+    const user = dbGet(`SELECT u.*, d.name AS department_name FROM users u LEFT JOIN departments d ON d.id=u.department_id WHERE email=${sqlQuote(body.email)} AND password=${sqlQuote(body.password)} AND active=1`);
