+    const asset = dbGet(`SELECT a.*, m.name AS model_name, m.category, m.unit_price, u.name AS holder_name, d.name AS department_name FROM assets a JOIN models m ON m.id=a.model_id LEFT JOIN users u ON u.id=a.holder_id LEFT JOIN departments d ON d.id=a.department_id WHERE a.id=${Number(p.id)}`);
+    if (!asset) return send(res, 404, { error: "资产不存在" });
