+    const events = dbAll(`SELECT e.*, u.name AS actor_name FROM asset_events e LEFT JOIN users u ON u.id=e.actor_id WHERE e.asset_id=${asset.id} ORDER BY e.id DESC`);
+    send(res, 200, { asset: { ...asset, status_label: STATUS[asset.status], net_value: Math.round(calcNetValue(asset)) }, events });
+  }),
