import http from "node:http";
import { readFile, mkdir } from "node:fs/promises";
import { existsSync } from "node:fs";
import { extname, join, resolve } from "node:path";
import { execFileSync } from "node:child_process";

const root = resolve(".");
const publicDir = join(root, "public");
const dbPath = process.env.DB_PATH || join(root, "data", "app.db");
const port = Number(process.env.PORT || 3000);

const STATUS = {
  available: "库存可用",
  reserved: "已占用",
  in_use: "使用中",
  repairing: "维修中",
  scrapped: "已报废",
  lost: "已丢失"
};

function sqlQuote(value) {
  if (value === null || value === undefined) return "NULL";
  if (typeof value === "number") return String(value);
  return `'${String(value).replaceAll("'", "''")}'`;
}

function sqlite(input, json = false) {
  const args = json ? ["-json", dbPath, input] : [dbPath, input];
  const out = execFileSync("sqlite3", args, { encoding: "utf8" }).trim();
  if (!json || !out) return json ? [] : out;
  return JSON.parse(out);
}

function dbRun(statements) {
  sqlite(Array.isArray(statements) ? statements.join(";\n") + ";" : statements);
}

function dbAll(query) {
  return sqlite(query, true);
}

function dbGet(query) {
  return dbAll(query)[0] || null;
}

async function initDb() {
  await mkdir(join(root, "data"), { recursive: true });
  dbRun(`
PRAGMA foreign_keys = ON;
CREATE TABLE IF NOT EXISTS departments (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL UNIQUE
);
CREATE TABLE IF NOT EXISTS users (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  email TEXT NOT NULL UNIQUE,
  password TEXT NOT NULL,
  role TEXT NOT NULL CHECK(role IN ('employee','manager','it','exec')),
  department_id INTEGER,
  manager_id INTEGER,
  active INTEGER NOT NULL DEFAULT 1,
  FOREIGN KEY(department_id) REFERENCES departments(id)
);
CREATE TABLE IF NOT EXISTS models (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  name TEXT NOT NULL,
  category TEXT NOT NULL,
  specs TEXT NOT NULL,
  unit_price REAL NOT NULL,
  min_stock INTEGER NOT NULL DEFAULT 2,
  keywords TEXT NOT NULL DEFAULT ''
);
CREATE TABLE IF NOT EXISTS assets (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  asset_no TEXT NOT NULL UNIQUE,
  serial_no TEXT,
  model_id INTEGER NOT NULL,
  department_id INTEGER,
  holder_id INTEGER,
  status TEXT NOT NULL CHECK(status IN ('available','reserved','in_use','repairing','scrapped','lost')),
  purchase_date TEXT NOT NULL,
  warranty_until TEXT NOT NULL,
  location TEXT,
  scrap_reason TEXT,
  FOREIGN KEY(model_id) REFERENCES models(id),
  FOREIGN KEY(holder_id) REFERENCES users(id),
  FOREIGN KEY(department_id) REFERENCES departments(id)
);
CREATE TABLE IF NOT EXISTS tickets (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  type TEXT NOT NULL CHECK(type IN ('apply','return','repair','transfer')),
  requester_id INTEGER NOT NULL,
  department_id INTEGER,
  model_id INTEGER,
  asset_id INTEGER,
  status TEXT NOT NULL,
  priority TEXT NOT NULL DEFAULT 'normal',
  title TEXT NOT NULL,
  description TEXT NOT NULL,
  ai_result TEXT,
  manager_decision TEXT,
  it_decision TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(requester_id) REFERENCES users(id)
);
CREATE TABLE IF NOT EXISTS ticket_events (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  ticket_id INTEGER NOT NULL,
  actor_id INTEGER,
  event TEXT NOT NULL,
  note TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(ticket_id) REFERENCES tickets(id)
);
CREATE TABLE IF NOT EXISTS asset_events (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  asset_id INTEGER NOT NULL,
  actor_id INTEGER,
  event TEXT NOT NULL,
  from_status TEXT,
  to_status TEXT,
  note TEXT,
  created_at TEXT NOT NULL DEFAULT CURRENT_TIMESTAMP,
  FOREIGN KEY(asset_id) REFERENCES assets(id)
