    if (!t) return send(res, 404, { error: "工单不存在" });
    if (t.status === "pending_manager") {
      requireRole(user, ["manager"]);
      if (t.department_id !== user.department_id) return send(res, 403, { error: "不能审批其他部门工单" });
      const next = b.decision === "reject" ? "rejected" : "pending_it";
      dbRun(`UPDATE tickets SET status=${sqlQuote(next)}, manager_decision=${sqlQuote(b.note || b.decision)}, updated_at=CURRENT_TIMESTAMP WHERE id=${id}`);
      addTicketEvent(id, user.id, b.decision === "reject" ? "manager_rejected" : "manager_approved", b.note || "");
      notify(t.requester_id, "主管审批结果", b.decision === "reject" ? "你的申领被主管驳回" : "主管已通过，等待 IT 审批");
      if (next === "pending_it") notify(5, "申领待 IT 审批", `${t.requester_name} 申请 ${t.model_name}`);
    } else if (["pending_it", "approved_waiting_assign"].includes(t.status)) {
      requireRole(user, ["it"]);
      if (b.decision === "reject") {
        dbRun(`UPDATE tickets SET status='rejected', it_decision=${sqlQuote(b.note || "驳回")}, updated_at=CURRENT_TIMESTAMP WHERE id=${id}`);
        addTicketEvent(id, user.id, "it_rejected", b.note || "");
        notify(t.requester_id, "IT 审批结果", "你的工单被 IT 驳回");
      } else {
        const asset = dbGet(`SELECT * FROM assets WHERE model_id=${t.model_id} AND status='available' ORDER BY id LIMIT 1`);
        if (!asset) return send(res, 400, { error: "无可用库存，不能分配" });
        dbRun(`UPDATE assets SET status='in_use', holder_id=${t.requester_id}, department_id=${t.department_id} WHERE id=${asset.id};
UPDATE tickets SET status='completed', asset_id=${asset.id}, it_decision=${sqlQuote(b.note || "已分配资产")}, updated_at=CURRENT_TIMESTAMP WHERE id=${id}`);
        addTicketEvent(id, user.id, "it_approved_assigned", `分配 ${asset.asset_no}`);
        addAssetEvent(asset.id, user.id, "assigned", "available", "in_use", `工单 #${id}`);
        notify(t.requester_id, "资产已分配", `IT 已为你分配 ${asset.asset_no}`);
      }
    } else {
      return send(res, 400, { error: "当前状态不可审批" });
    }
    audit(user, "approve_ticket", "ticket", id, b.decision || "approve");
    send(res, 200, { ok: true });
  }),
  route("POST", "/api/tickets/:id/complete", async (req, res, user, p) => {
