    if (!t) return send(res, 404, { error: "工单不存在" });
    if (t.type === "return") {
      const asset = dbGet(`SELECT * FROM assets WHERE id=${t.asset_id}`);
      dbRun(`UPDATE assets SET status='available', holder_id=NULL, department_id=NULL, location='IT 仓库' WHERE id=${asset.id};
UPDATE tickets SET status='completed', updated_at=CURRENT_TIMESTAMP WHERE id=${t.id}`);
      addAssetEvent(asset.id, user.id, "returned", asset.status, "available", b.note || "");
      notify(t.requester_id, "归还已完成", "IT 已确认接收你的归还资产");
    } else if (t.type === "repair") {
      const asset = dbGet(`SELECT * FROM assets WHERE id=${t.asset_id}`);
      const next = b.result === "scrap" ? "scrapped" : "in_use";
      dbRun(`UPDATE assets SET status=${sqlQuote(next)}, scrap_reason=${sqlQuote(b.note || "")} WHERE id=${asset.id};
UPDATE tickets SET status='completed', updated_at=CURRENT_TIMESTAMP WHERE id=${t.id}`);
      addAssetEvent(asset.id, user.id, next === "scrapped" ? "scrapped" : "repair_done", asset.status, next, b.note || "");
      notify(t.requester_id, "维修已完成", next === "scrapped" ? "设备无法修复，已报废" : "设备已修复，可继续使用");
    } else return send(res, 400, { error: "该工单不能用完结操作" });
    addTicketEvent(t.id, user.id, "completed", b.note || "");
    audit(user, "complete_ticket", "ticket", t.id, b.note || "");
