    if (dbGet(`SELECT id FROM assets WHERE asset_no=${sqlQuote(b.asset_no)}`)) return send(res, 409, { error: "资产编号已存在，重复扫码被拒绝" });
    dbRun(`INSERT INTO assets(asset_no,serial_no,model_id,status,purchase_date,warranty_until,location) VALUES(${sqlQuote(b.asset_no)},${sqlQuote(b.serial_no || "")},${Number(b.model_id)},'available',${sqlQuote(b.purchase_date)},${sqlQuote(b.warranty_until)},${sqlQuote(b.location || "IT 仓库")})`);
    const id = dbGet("SELECT last_insert_rowid() AS id").id;
    addAssetEvent(id, user.id, "inbound", null, "available", "扫码/手动入库");
    audit(user, "inbound_asset", "asset", id, b.asset_no);
    send(res, 201, { id });
  }),
  route("POST", "/api/inventory/scan", async (req, res, user) => {
    requireRole(user, ["it"]);
