    const codes = Array.isArray(b.asset_nos) ? b.asset_nos : String(b.asset_nos || "").split(/[,\n\s]+/).filter(Boolean);
    const rows = dbAll(`SELECT asset_no,status FROM assets`);
    const known = new Set(rows.map(r => r.asset_no));
    const scanned = new Set(codes);
    const missing = rows.filter(r => !scanned.has(r.asset_no) && r.status !== "scrapped").map(r => r.asset_no);
    const unknown = [...scanned].filter(c => !known.has(c));
    audit(user, "inventory_scan", "inventory", null, `scanned=${codes.length}`);
