  route("GET", "/api/exec/dashboard", async (req, res, user) => {
    requireRole(user, ["exec", "it"]);
    const assets = dbAll(`SELECT a.*, m.unit_price, m.name AS model_name, d.name AS department_name FROM assets a JOIN models m ON m.id=a.model_id LEFT JOIN departments d ON d.id=a.department_id`);
    const total = assets.length;
    const netValue = Math.round(assets.reduce((sum, a) => sum + calcNetValue(a), 0));
    const byDept = dbAll(`SELECT COALESCE(d.name,'库存/未分配') AS name, COUNT(*) AS count FROM assets a LEFT JOIN departments d ON d.id=a.department_id GROUP BY COALESCE(d.name,'库存/未分配')`);
    const lowStock = dbAll(`SELECT m.name, m.min_stock, (SELECT COUNT(*) FROM assets a WHERE a.model_id=m.id AND a.status='available') AS available FROM models m WHERE available < m.min_stock`);
    const now = Date.now();
    const ages = { "<1年": 0, "1-3年": 0, "3-5年": 0, ">5年": 0 };
    for (const a of assets) {
      const y = (now - new Date(a.purchase_date).getTime()) / (365 * 24 * 3600 * 1000);
      if (y < 1) ages["<1年"]++; else if (y < 3) ages["1-3年"]++; else if (y < 5) ages["3-5年"]++; else ages[">5年"]++;
    }
    send(res, 200, { total, netValue, byDept, ageDistribution: ages, lowStock, alerts: lowStock.map(x => `${x.name} 库存 ${x.available}，低于安全线 ${x.min_stock}`) });
  }),
  route("GET", "/api/exec/insights", async (req, res, user) => {
    requireRole(user, ["exec", "it"]);
    const lowStock = dbAll(`SELECT m.name, m.min_stock, (SELECT COUNT(*) FROM assets a WHERE a.model_id=m.id AND a.status='available') AS available FROM models m WHERE available < m.min_stock`);
    let text = null;
    try { text = await callLLM("executive_insight", "生成采购和调拨建议", { lowStock }); } catch (e) { text = null; }
    if (!text) text = lowStock.length
      ? `建议优先采购：${lowStock.map(x => `${x.name} ${Math.max(1, x.min_stock * 2 - x.available)} 台`).join("、")}。理由：当前库存低于安全线，可能影响新员工入职和临时替换。`
      : "当前安全库存健康。建议继续关注超过 3 年资产与维修频率，下一轮采购以替换老旧设备为主。";
    send(res, 200, { aiAvailable: Boolean(process.env.AI_API_KEY), insight: text, requiresHumanConfirmation: true });
  })
];

async function serveStatic(req, res) {
  const url = new URL(req.url, "http://localhost");
  let filePath = join(publicDir, url.pathname === "/" ? "index.html" : url.pathname);
  if (!filePath.startsWith(publicDir)) {
    res.writeHead(403); res.end("Forbidden"); return;
  }
  try {
    const data = await readFile(filePath);
    const type = { ".html": "text/html", ".css": "text/css", ".js": "application/javascript" }[extname(filePath)] || "application/octet-stream";
    res.writeHead(200, { "Content-Type": `${type}; charset=utf-8` });
    res.end(data);
  } catch {
    const data = await readFile(join(publicDir, "index.html"));
    res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
    res.end(data);
  }
}

await initDb();
if (process.argv.includes("--init-only")) process.exit(0);

const server = http.createServer(async (req, res) => {
  try {
    const url = new URL(req.url, "http://localhost");
    if (!url.pathname.startsWith("/api/")) return serveStatic(req, res);
    const match = routes.find(r => r.method === req.method && r.regex.test(url.pathname));
    if (!match) return send(res, 404, { error: "接口不存在" });
    const m = url.pathname.match(match.regex);
    const params = Object.fromEntries(match.keys.map((k, i) => [k, m[i + 1]]));
    const user = url.pathname === "/api/login" ? null : getUser(req);
    if (url.pathname !== "/api/login" && !user) return send(res, 401, { error: "请先登录" });
    await match.handler(req, res, user, params);
  } catch (err) {
    send(res, err.status || 500, { error: err.message || "服务器错误" });
  }
});

server.listen(port, () => {
  console.log(`AI IT Asset Platform running at http://localhost:${port}`);
});

