  ["it-inbound", "入库操作", ["it"]],
  ["it-inventory", "盘点任务", ["it"]],
  ["it-users", "用户管理", ["it"]],
  ["it-audit", "审计日志", ["it"]],
  ["exec-dashboard", "资产看板", ["exec", "it"]],
  ["exec-insights", "AI 洞察", ["exec", "it"]]
];

const $ = (sel) => document.querySelector(sel);
const app = $("#app");

async function api(path, options = {}) {
  const res = await fetch(path, {
    ...options,
    headers: {
      "Content-Type": "application/json",
      "X-User-Id": state.user?.id || "",
      ...(options.headers || {})
    }
  });
  const data = await res.json();
  if (!res.ok) throw new Error(data.error || "请求失败");
  return data;
}

function money(n) {
  return Number(n || 0).toLocaleString("zh-CN", { style: "currency", currency: "CNY", maximumFractionDigits: 0 });
}

function toast(text) {
  const el = document.createElement("div");
  el.className = "toast";
  el.textContent = text;
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 2600);
}

function badge(status) {
  const map = {
    available: ["库存可用", "good"],
    in_use: ["使用中", "info"],
    repairing: ["维修中", "warn"],
    scrapped: ["已报废", "bad"],
    lost: ["已丢失", "bad"],
    pending_manager: ["待主管审批", "warn"],
    pending_it: ["待 IT 审批", "warn"],
    return_pending: ["待 IT 接收", "warn"],
    it_processing: ["IT 处理中", "info"],
    completed: ["已完成", "good"],
    rejected: ["已驳回", "bad"]
  };
  const [label, cls] = map[status] || [status, ""];
  return `<span class="badge ${cls}">${label}</span>`;
}

function setView(view) {
  state.view = view;
  location.hash = view;
  render();
}

window.addEventListener("hashchange", () => {
  state.view = location.hash.replace("#", "") || "home";
  render();
});

function renderLogin() {
  app.innerHTML = `
    <main class="login">
      <section class="login-card">
        <h2>登录</h2>
        <p class="muted">默认密码都是 password</p>
        <form class="form" id="loginForm">
          <label>邮箱<input name="email" value="employee@example.com"></label>
          <label>密码<input name="password" type="password" value="password"></label>
          <button class="primary">进入平台</button>
        </form>
        <div class="quick-accounts">
          ${[
            ["employee@example.com", "员工"],
            ["manager@example.com", "部门主管"],
            ["it@example.com", "IT 管理员"],
            ["exec@example.com", "管理层"]
          ].map(([email, label]) => `<button data-email="${email}">${label}账号：${email}</button>`).join("")}
        </div>
      </section>
      <section class="login-hero">
        <h1>AI IT 资产与设备流转管理系统</h1>
        <p>覆盖申领、审批、领用、归还、报修、入库、盘点、追溯、通知、审计和管理看板。系统使用真实数据库保存数据，AI 能力通过外部模型配置接入，并在未配置时提供可解释降级。</p>
      </section>
    </main>`;
  $("#loginForm").addEventListener("submit", async (e) => {
    e.preventDefault();
    const body = Object.fromEntries(new FormData(e.currentTarget));
    try {
      const data = await api("/api/login", { method: "POST", body: JSON.stringify(body) });
      state.user = data.user;
      localStorage.setItem("asset_user", JSON.stringify(data.user));
      setView(data.user.role === "it" ? "it-home" : data.user.role === "exec" ? "exec-dashboard" : "home");
    } catch (err) { toast(err.message); }
  });
  document.querySelectorAll("[data-email]").forEach(btn => btn.onclick = () => {
    document.querySelector("[name=email]").value = btn.dataset.email;
  });
}

function shell(content, title = "") {
  const allowed = routes.filter(r => r[2].includes(state.user.role));
  app.innerHTML = `
    <div class="app-shell">
      <aside class="sidebar">
        <div class="brand">AI 资产平台</div>
        <div class="user-box">
          <strong>${state.user.name}</strong><br>${state.user.department_name || "平台"} · ${roleName(state.user.role)}
        </div>
        <nav class="nav">
          ${allowed.map(([id, label]) => `<button class="${state.view === id ? "active" : ""}" data-view="${id}">${label}</button>`).join("")}
        </nav>
      </aside>
      <main class="main">
        <div class="topbar">
          <h1>${title}</h1>
          <button id="logout">退出</button>
        </div>
        ${content}
      </main>
    </div>`;
  document.querySelectorAll("[data-view]").forEach(b => b.onclick = () => setView(b.dataset.view));
  $("#logout").onclick = () => {
    localStorage.removeItem("asset_user");
    state.user = null;
    render();
  };
}

