  const data = await api("/api/users");
  shell(`<div class="table-wrap"><table><thead><tr><th>姓名</th><th>邮箱</th><th>角色</th><th>部门</th><th>持有资产</th><th>状态</th><th>操作</th></tr></thead>
  <tbody>${data.users.map(u => `<tr><td>${u.name}</td><td>${u.email}</td><td>${roleName(u.role)}</td><td>${u.department_name || "-"}</td><td>${u.asset_count}</td><td>${u.active ? "在职" : "离职"}</td><td>${u.active ? `<button data-offboard="${u.id}">标记离职</button>` : ""}</td></tr>`).join("")}</tbody></table></div>`, "用户管理");
  document.querySelectorAll("[data-offboard]").forEach(btn => btn.onclick = async () => {
    const data = await api(`/api/users/${btn.dataset.offboard}/offboard`, { method: "POST", body: "{}" });
    toast(`已标记离职，未归还 ${data.unreturned.length} 台`);
    render();
  });
}

async function notifications() {
  const data = await api("/api/notifications");
  shell(`<div class="list">${data.notifications.map(n => `<div class="item"><h3>${n.title}</h3><p>${n.body}</p><p class="muted">${n.created_at} ${n.read_at ? "已读" : "未读"}</p>${n.read_at ? "" : `<button data-read="${n.id}">标记已读</button>`}</div>`).join("") || "暂无通知"}</div>`, "通知中心");
  document.querySelectorAll("[data-read]").forEach(btn => btn.onclick = async () => {
    await api(`/api/notifications/${btn.dataset.read}/read`, { method: "POST", body: "{}" });
    render();
  });
}

async function audit() {
  const data = await api("/api/audit");
  shell(`<div class="table-wrap"><table><thead><tr><th>ID</th><th>操作者</th><th>动作</th><th>对象</th><th>详情</th><th>时间</th></tr></thead>
  <tbody>${data.logs.map(l => `<tr><td>${l.id}</td><td>${l.actor_name || "系统"}</td><td>${l.action}</td><td>${l.entity_type} #${l.entity_id || ""}</td><td>${l.detail || ""}</td><td>${l.created_at}</td></tr>`).join("")}</tbody></table></div>`, "审计日志");
}

async function execDashboard() {
  const data = await api("/api/exec/dashboard");
  const max = Math.max(...data.byDept.map(x => x.count), 1);
  shell(`
    <section class="grid cols-3">
      <div class="panel metric"><span>资产总数</span><strong>${data.total}</strong></div>
      <div class="panel metric"><span>账面净值</span><strong>${money(data.netValue)}</strong></div>
      <div class="panel metric"><span>异常告警</span><strong>${data.alerts.length}</strong></div>
    </section>
    <section class="grid cols-2" style="margin-top:14px">
      <div class="panel"><h2>部门分布</h2><div class="bars">${data.byDept.map(x => `<div class="bar"><span>${x.name}</span><span><i style="width:${x.count / max * 100}%"></i></span><b>${x.count}</b></div>`).join("")}</div></div>
      <div class="panel"><h2>资产年龄</h2><div class="bars">${Object.entries(data.ageDistribution).map(([k,v]) => `<div class="bar"><span>${k}</span><span><i style="width:${v / data.total * 100}%"></i></span><b>${v}</b></div>`).join("")}</div></div>
    </section>
    <section class="panel" style="margin-top:14px"><h2>异常告警</h2><div class="list">${data.alerts.map(a => `<div class="item">${a}</div>`).join("") || "暂无异常"}</div></section>`, "资产看板大屏");
}

async function insights() {
  const data = await api("/api/exec/insights");
  shell(`<section class="panel"><h2>AI 洞察</h2><p>${data.insight}</p><p class="muted">AI 建议需要人工确认后才能执行。当前 AI 服务：${data.aiAvailable ? "已接入" : "未配置，展示规则兜底建议"}</p><button class="primary">了解详情</button></section>`, "AI 洞察");
}

async function chat() {
  shell(`<div class="chat-box" id="chatBox">${state.chat.map(m => `<div class="msg ${m.me ? "me" : ""}">${m.text}</div>`).join("")}</div>
    <form class="toolbar" id="chatForm" style="margin-top:12px"><input name="message" placeholder="问：我现在有哪些设备 / 我的笔记本什么时候过保 / 我要报修"><button class="primary">发送</button></form>`, "AI 助手");
  $("#chatForm").onsubmit = async e => {
    e.preventDefault();
    const message = new FormData(e.currentTarget).get("message");
    if (!message) return;
    state.chat.push({ me: true, text: message });
    const data = await api("/api/chat", { method: "POST", body: JSON.stringify({ message }) });
    state.chat.push({ me: false, text: data.answer });
    chat();
  };
}

async function profile() {
  shell(`<section class="panel"><h2>${state.user.name}</h2><p>${state.user.email}</p><p>${state.user.department_name || "-"} · ${roleName(state.user.role)}</p><p class="muted">密码修改入口已预留，演示账号统一使用默认密码。</p></section>`, "个人设置");
}

async function render() {
  if (!state.user) return renderLogin();
  try {
    const handlers = {
      home, "my-assets": () => myAssets(false), apply: applyView, tickets: () => tickets(false), chat, notifications, profile,
      approvals, "dept-board": () => myAssets(true), "it-home": itHome, "it-tickets": () => tickets(true), "it-assets": itAssets,
      "it-models": itModels, "it-inbound": inbound, "it-inventory": inventory, "it-users": users, "it-audit": audit,
      "exec-dashboard": execDashboard, "exec-insights": insights
    };
    const allowed = routes.find(r => r[0] === state.view)?.[2]?.includes(state.user.role);
    if (!allowed) state.view = state.user.role === "it" ? "it-home" : state.user.role === "exec" ? "exec-dashboard" : "home";
    await handlers[state.view]();
  } catch (err) {
    shell(`<section class="panel"><h2>出错了</h2><p>${err.message}</p><button class="primary" onclick="location.reload()">刷新</button></section>`, "错误");
  }
}

render();

:root {
  --bg: #f5f7fb;
  --panel: #ffffff;
  --text: #172033;
  --muted: #667085;
  --line: #d9e0ec;
  --blue: #2667d9;
  --green: #16845b;
  --orange: #b76b00;
  --red: #c83f49;
  --cyan: #00758f;
}

* { box-sizing: border-box; }
body {
  margin: 0;
  background: var(--bg);
  color: var(--text);
  font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", sans-serif;
}
button, input, textarea, select { font: inherit; }
button {
  border: 1px solid var(--line);
  background: #fff;
  color: var(--text);
  border-radius: 6px;
  padding: 9px 12px;
  cursor: pointer;
}
button.primary { background: var(--blue); border-color: var(--blue); color: #fff; }
button.danger { background: var(--red); border-color: var(--red); color: #fff; }
button.ghost { background: transparent; }
input, textarea, select {
  width: 100%;
  border: 1px solid var(--line);
  border-radius: 6px;
  padding: 10px 11px;
  background: #fff;
}
textarea { min-height: 96px; resize: vertical; }
.login {
  min-height: 100vh;
  display: grid;
  grid-template-columns: minmax(320px, 420px) 1fr;
}
.login-card {
  background: #fff;
  padding: 44px;
  border-right: 1px solid var(--line);
}
.login-hero {
  padding: 48px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  background: linear-gradient(135deg, #eaf2ff, #f9fbff 45%, #eef8f5);
}
.login-hero h1 { font-size: 42px; margin: 0 0 16px; letter-spacing: 0; }
.login-hero p { color: var(--muted); max-width: 700px; line-height: 1.7; }
.quick-accounts { display: grid; gap: 8px; margin-top: 18px; }
.app-shell { display: grid; grid-template-columns: 248px 1fr; min-height: 100vh; }
.sidebar {
  background: #111827;
  color: #fff;
  padding: 22px 16px;
}
.brand { font-weight: 750; margin-bottom: 18px; font-size: 18px; }
.user-box { color: #cbd5e1; font-size: 13px; border-bottom: 1px solid #293244; padding-bottom: 16px; margin-bottom: 16px; }
.nav { display: grid; gap: 6px; }
.nav button {
  color: #dbe4f0;
  border-color: transparent;
  background: transparent;
  text-align: left;
  padding: 10px 12px;
}
.nav button.active, .nav button:hover { background: #22304a; color: #fff; }
.main { padding: 24px; overflow: auto; }
.topbar { display: flex; justify-content: space-between; align-items: center; gap: 14px; margin-bottom: 18px; }
.topbar h1 { margin: 0; font-size: 26px; letter-spacing: 0; }
.grid { display: grid; gap: 14px; }
.grid.cols-2 { grid-template-columns: repeat(2, minmax(0, 1fr)); }
.grid.cols-3 { grid-template-columns: repeat(3, minmax(0, 1fr)); }
.grid.cols-4 { grid-template-columns: repeat(4, minmax(0, 1fr)); }
.panel {
  background: var(--panel);
  border: 1px solid var(--line);
  border-radius: 8px;
  padding: 16px;
}
.metric { display: grid; gap: 6px; }
.metric strong { font-size: 30px; }
.metric span { color: var(--muted); font-size: 13px; }
.toolbar { display: flex; gap: 10px; align-items: center; flex-wrap: wrap; margin-bottom: 12px; }
.table-wrap { overflow: auto; border: 1px solid var(--line); border-radius: 8px; background: #fff; }
table { width: 100%; border-collapse: collapse; min-width: 760px; }
th, td { padding: 11px 12px; border-bottom: 1px solid var(--line); text-align: left; vertical-align: top; }
th { background: #f8fafc; color: #475467; font-size: 13px; }
tr:last-child td { border-bottom: none; }
.badge {
  display: inline-flex;
  align-items: center;
  border-radius: 999px;
  padding: 3px 9px;
  font-size: 12px;
  border: 1px solid var(--line);
  background: #f8fafc;
}
.badge.good { color: var(--green); background: #ecfdf5; border-color: #a7f3d0; }
.badge.warn { color: var(--orange); background: #fff7ed; border-color: #fed7aa; }
.badge.bad { color: var(--red); background: #fff1f2; border-color: #fecdd3; }
.badge.info { color: var(--cyan); background: #ecfeff; border-color: #a5f3fc; }
.form { display: grid; gap: 12px; max-width: 860px; }
.row { display: grid; grid-template-columns: repeat(2, minmax(0, 1fr)); gap: 12px; }
.list { display: grid; gap: 10px; }
.item {
  border: 1px solid var(--line);
  border-radius: 8px;
  padding: 12px;
  background: #fff;
}
.item h3 { margin: 0 0 6px; font-size: 16px; }
.muted { color: var(--muted); }
.actions { display: flex; gap: 8px; flex-wrap: wrap; margin-top: 10px; }
.timeline { border-left: 2px solid var(--line); margin-left: 8px; padding-left: 14px; display: grid; gap: 12px; }
.timeline div { position: relative; }
.timeline div::before {
  content: "";
  position: absolute;
  width: 9px;
  height: 9px;
  border-radius: 50%;
  background: var(--blue);
  left: -20px;
  top: 5px;
}
.chat-box { height: 420px; overflow: auto; background: #fff; border: 1px solid var(--line); border-radius: 8px; padding: 14px; display: grid; align-content: start; gap: 10px; }
.msg { max-width: 78%; padding: 10px 12px; border-radius: 8px; background: #eef2ff; }
.msg.me { justify-self: end; background: #dcfce7; }
.bars { display: grid; gap: 10px; }
.bar { display: grid; grid-template-columns: 110px 1fr 42px; gap: 10px; align-items: center; }
.bar span:nth-child(2) { height: 12px; border-radius: 999px; background: #dbeafe; overflow: hidden; }
.bar i { display: block; height: 100%; background: var(--blue); }
.toast {
  position: fixed;
  right: 18px;
  bottom: 18px;
  background: #111827;
  color: #fff;
  padding: 12px 14px;
  border-radius: 8px;
  box-shadow: 0 12px 30px rgba(0,0,0,.18);
}
@media (max-width: 900px) {
  .login { grid-template-columns: 1fr; }
  .login-hero { display: none; }
  .app-shell { grid-template-columns: 1fr; }
  .sidebar { position: static; }
  .grid.cols-2, .grid.cols-3, .grid.cols-4, .row { grid-template-columns: 1fr; }
  .main { padding: 16px; }
}

